import React from "react";
import { Link } from "react-router-dom";

const Welcome = () => {
  return (
    <div style={pageStyle}>
      <h1>MindCare AI</h1>
      <Link to="/login">
        <button style={btnStyle}>Get Started</button>
      </Link>
    </div>
  );
};

export default Welcome;

const pageStyle = {
  height: "100vh",
  background: "#6f75ff",
  display: "flex",
  flexDirection: "column",
  justifyContent: "center",
  alignItems: "center",
  color: "white",
};

const btnStyle = {
  padding: "12px 20px",
  fontSize: "16px",
};
